{"expression": "// Check brand filter dropdown options
let selects = document.querySelectorAll('select, [role="combobox"]')
let brandCombo = null;
selects.forEach(s => { if (s.textContent.includes('AgriTool')) brandCombo = s; })
console.log('Brand combo found:', !!brandCombo)
// Also check the brand filter if it still shows options
let comboBoxes = document.querySelectorAll('[role="combobox"]')
comboBoxes.forEach((c, i) => {
  console.log(`Combo ${i}: text="${c.textContent?.slice(0,50)}"`)
})"}

{"expression": "// Check current price and brand state visually
// 1. Are brands gone from the filter? 
const filters = document.querySelectorAll('[class*="select"], [class*="filter"]');
// 2. Check if NUEVO badges are gone
const badges = [...document.querySelectorAll('span')].filter(s => s.textContent === 'NUEVO' || s.textContent === 'OFERTA');
`NUEVO/OFERTA badges: ${badges.length}, Filters: ${filters.length}`
"}

{"expression": "// Check Gs. price presence
const prices = [...document.querySelectorAll('[class*="font-bold"]')].filter(el => el.textContent.includes('Gs.'));
`Gs. prices found: ${prices.length}, first: ${prices[0]?.textContent?.slice(0,20) || 'none'}`
"}

{"expression": "// Check brand filter
const brandFilter = document.querySelectorAll('[role="combobox"]')[2];
const options = brandFilter ? [...brandFilter.querySelectorAll('[role="option"], li, option')].map(o => o.textContent.trim()).filter(Boolean) : [];
`Brand filter options: ${options.length > 0 ? options.slice(0,5).join(', ') : 'empty'}`
"}

